arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars now return "" instead of null.
        // Use a non-empty sentinel to distinguish "not set" (null) from "explicitly empty" ("").
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly empty");
        }
    }
}

